#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int *a = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; ++i) scanf("%d", &a[i]);
        int *len = (int*)malloc(N * sizeof(int));
        int *cnt = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; ++i) { len[i]=1; cnt[i]=1; }
        int maxLen = 1;
        for (int i = 0; i < N; ++i) {
            for (int j = 0; j < i; ++j) {
                if (a[i] > a[j]) {
                    if (len[j] + 1 > len[i]) {
                        len[i] = len[j] + 1;
                        cnt[i] = cnt[j];
                    } else if (len[j] + 1 == len[i]) {
                        cnt[i] = (cnt[i] + cnt[j]) % MOD;
                    }
                }
            }
            if (len[i] > maxLen) maxLen = len[i];
        }
        long long ans = 0;
        for (int i = 0; i < N; ++i) if (len[i] == maxLen) ans = (ans + cnt[i]) % MOD;
        printf("%lld\n", ans);
        free(a); free(len); free(cnt);
    }
    return 0;
}

