import sys
MOD = 1000000007

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        a = [int(next(it)) for _ in range(N)]
        length = [1] * N
        count = [1] * N
        max_len = 1
        for i in range(N):
            for j in range(i):
                if a[i] > a[j]:
                    if length[j] + 1 > length[i]:
                        length[i] = length[j] + 1
                        count[i] = count[j]
                    elif length[j] + 1 == length[i]:
                        count[i] = (count[i] + count[j]) % MOD
            if length[i] > max_len:
                max_len = length[i]
        ans = 0
        for i in range(N):
            if length[i] == max_len:
                ans = (ans + count[i]) % MOD
        out.append(str(ans))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

